#include <stdio.h>
int max(int a, int b) { return (a > b) ? a : b; }
int knapsack(int* C, int* P, int* T, int N, int W) {
    int dp[N + 1][W + 1];
    for (int i = 0; i <= N; i++) {
        for (int w = 0; w <= W; w++) {
            if (i == 0 || w == 0)
                dp[i][w] = 0;
            else if (T[i - 1] <= w)
                dp[i][w] = max(C[i - 1] * P[i - 1] + dp[i - 1][w - T[i - 1]], dp[i - 1][w]);
            else
                dp[i][w] = dp[i - 1][w];
        }
    }
    return dp[N][W];
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, W;
        scanf("%d %d", &N, &W);
        int C[N], P[N], T[N];
        for (int i = 0; i < N; i++)
            scanf("%d %d %d", &C[i], &P[i], &T[i]);
        printf("%d\n", knapsack(C, P, T, N, W));
    }
    return 0;
}

